## Solution 1: Topological Order + DP with (node, edges_used) states

This solution uses a topological sort and dynamic programming where `dp[node][edges]` stores the max sum to reach `node` with exactly `edges` edges used. The answer is the max over `dp[n-1][e]` for `e <= k`.

```python
from collections import deque, defaultdict

def max_weighted_path(n, edges, weights, k):
    # Edge case: if n=1, path from 0 to 0 is just the node itself with 0 edges
    if n == 1:
        return weights[0] if k >= 0 else -1

    graph = [[] for _ in range(n)]
    indeg = [0]*n
    for u,v in edges:
        graph[u].append(v)
        indeg[v] += 1

    # Topological sort
    q = deque()
    for i in range(n):
        if indeg[i] == 0:
            q.append(i)

    topo = []
    while q:
        u = q.popleft()
        topo.append(u)
        for v in graph[u]:
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)

    # Initialize dp: dp[node][edges_used] = max sum
    # Use dict for space efficiency
    dp = [dict() for _ in range(n)]
    dp[0][0] = weights[0]

    for u in topo:
        for used_edges, curr_sum in dp[u].items():
            if used_edges == k:
                continue
            for v in graph[u]:
                next_edges = used_edges + 1
                next_sum = curr_sum + weights[v]
                if next_edges <= k:
                    if next_edges not in dp[v] or dp[v][next_edges] < next_sum:
                        dp[v][next_edges] = next_sum

    # Find max sum at node n-1 with edges <= k
    if not dp[n-1]:
        return -1
    return max(dp[n-1].values())
```

