## Solution 5: DP with shortest path length filtering + max sum

First, compute shortest path length in edges from 0 to all nodes using BFS, then only consider states with edges_used <= k. Then do DP with topological order.

```python
from collections import deque

def max_weighted_path(n, edges, weights, k):
    if n == 1:
        return weights[0] if k >= 0 else -1

    graph = [[] for _ in range(n)]
    rev_graph = [[] for _ in range(n)]
    for u,v in edges:
        graph[u].append(v)
        rev_graph[v].append(u)

    # shortest path length (edges) from 0 to all nodes
    dist = [float('inf')] * n
    dist[0] = 0
    q = deque([0])
    while q:
        u = q.popleft()
        for v in graph[u]:
            if dist[v] > dist[u] + 1:
                dist[v] = dist[u] + 1
                q.append(v)

    if dist[n-1] == float('inf') or dist[n-1] > k:
        return -1

    indeg = [0]*n
    for u,v in edges:
        indeg[v] += 1

    q = deque()
    for i in range(n):
        if indeg[i] == 0:
            q.append(i)

    topo = []
    while q:
        u = q.popleft()
        topo.append(u)
        for v in graph[u]:
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)

    INF = float('-inf')
    dp = [INF]*n
    dp[0] = weights[0]

    for u in topo:
        if dp[u] == INF:
            continue
        for v in graph[u]:
            # only update if dist[v] <= k (path length constraint)
            if dist[v] <= k:
                dp[v] = max(dp[v], dp[u] + weights[v])

    return dp[n-1] if dp[n-1] != INF else -1
```

